async function getEndedAuctionsByMerchant(merchantId, hideAfterDays, showUnsoldEnded = 0) {
  const db = await getDb();
  if (!db) return [];
  try {
    const { users: usersTable } = await Promise.resolve().then(() => (init_schema(), schema_exports));
    const conds = [
      eq(auctions.createdBy, merchantId),
      sql`${auctions.status} = 'ended'`,
      sql`(${auctions.archived} = 0 OR ${auctions.archived} IS NULL)`
    ];
    if (hideAfterDays > 0) {
      const cutoff = new Date(Date.now() - hideAfterDays * 24 * 60 * 60 * 1e3);
      conds.push(gte(auctions.endTime, cutoff));
    }
    if (!showUnsoldEnded) {
      conds.push(isNotNull(auctions.highestBidderId));
    }
    const rows = await db.select({
      id: auctions.id,
      title: auctions.title,
      currentPrice: auctions.currentPrice,
      startingPrice: auctions.startingPrice,
      endTime: auctions.endTime,
      status: auctions.status,
      currency: auctions.currency,
      category: auctions.category,
      bidIncrement: auctions.bidIncrement,
      createdBy: auctions.createdBy,
      highestBidderId: auctions.highestBidderId,
      highestBidderName: usersTable.name,
      highestBidderIsAnonymous: sql`COALESCE((SELECT isAnonymous FROM bids WHERE auctionId = ${auctions.id} AND userId = ${auctions.highestBidderId} ORDER BY id DESC LIMIT 1), 0)`,
      bidCount: sql`(SELECT COUNT(*) FROM bids WHERE auctionId = ${auctions.id})`,
      createdAt: auctions.createdAt,
      antiSnipeEnabled: auctions.antiSnipeEnabled,
      antiSnipeMinutes: auctions.antiSnipeMinutes,
      extendMinutes: auctions.extendMinutes,
      displayMode: auctions.displayMode,
      sellerName: sql`(SELECT name FROM users WHERE id = ${auctions.createdBy})`,
      sellerPhotoUrl: sql`(SELECT COALESCE(NULLIF(TRIM(ma.merchantIcon),''), NULLIF(TRIM(u.photoUrl),'')) FROM users u LEFT JOIN merchantApplications ma ON ma.userId = u.id AND ma.status = 'approved' WHERE u.id = ${auctions.createdBy} LIMIT 1)`,
      fbShareTemplate: sql`(SELECT fbShareTemplate FROM merchant_settings WHERE userId = ${auctions.createdBy} LIMIT 1)`
    }).from(auctions).leftJoin(usersTable, eq(auctions.highestBidderId, usersTable.id)).where(and(...conds)).orderBy(desc(auctions.endTime));
    return await Promise.all(rows.map(async (row) => {
      const imgs = await getAuctionImages(row.id);
      const highestBidderName = row.highestBidderIsAnonymous === 1 ? "\u{1F575}\uFE0F \u533F\u540D\u8CB7\u5BB6" : row.highestBidderName ?? null;
      return { ...row, coverImage: imgs[0]?.imageUrl ?? null, images: imgs, highestBidderName };
    }));
  } catch (err) {
    console.error("[getEndedAuctionsByMerchant] error:", err);
    return [];
  }
}
async function getRecentlyEndedForMainPage() {
  const pool = await getRawPool();
  if (!pool) return [];
  const mapRow = (r) => ({
    id: Number(r.id),
    title: String(r.title ?? ""),
    endTime: r.endTime,
    createdBy: Number(r.createdBy),
    currency: r.currency != null ? String(r.currency) : null,
    sellerName: r.sellerName != null ? String(r.sellerName) : null,
    coverImage: r.coverImage != null ? String(r.coverImage) : null
  });
  try {
    const [rows] = await pool.execute(
      `SELECT
        a.id, a.title, a.endTime, a.createdBy, a.currency,
        (SELECT name FROM users WHERE id = a.createdBy LIMIT 1) AS sellerName,
        (SELECT imageUrl FROM auctionImages WHERE auctionId = a.id ORDER BY id ASC LIMIT 1) AS coverImage
      FROM auctions a
      WHERE a.status = 'ended'
        AND (a.archived = 0 OR a.archived IS NULL)
        AND COALESCE((SELECT showEndedOnMainPage FROM merchant_settings WHERE userId = a.createdBy LIMIT 1), 1) = 1
        AND a.endTime >= DATE_SUB(NOW(), INTERVAL LEAST(COALESCE(
          (SELECT mainPageEndedDays FROM merchant_settings WHERE userId = a.createdBy LIMIT 1), 7
        ), 30) DAY)
        AND NOT (a.highestBidderId IS NULL AND COALESCE((SELECT showUnsoldEnded FROM merchant_settings WHERE userId = a.createdBy LIMIT 1), 0) = 0)
      ORDER BY a.endTime DESC
      LIMIT 200`
    );
    const result = rows.map(mapRow);
    console.log("[getRecentlyEndedForMainPage] full query returned", result.length, "rows");
    return result;
  } catch (err1) {
    console.warn("[getRecentlyEndedForMainPage] full query failed, trying fallback:", err1.message);
    try {
      const [rows] = await pool.execute(
        `SELECT
          a.id, a.title, a.endTime, a.createdBy, a.currency,
          (SELECT name FROM users WHERE id = a.createdBy LIMIT 1) AS sellerName,
          (SELECT imageUrl FROM auctionImages WHERE auctionId = a.id ORDER BY id ASC LIMIT 1) AS coverImage
        FROM auctions a
        WHERE a.status = 'ended'
          AND (a.archived = 0 OR a.archived IS NULL)
          AND a.endTime >= DATE_SUB(NOW(), INTERVAL 2 DAY)
          AND a.highestBidderId IS NOT NULL
        ORDER BY a.endTime DESC
        LIMIT 200`
      );
      const result = rows.map(mapRow);
      console.log("[getRecentlyEndedForMainPage] fallback query returned", result.length, "rows");
      return result;
    } catch (err2) {
      console.error("[getRecentlyEndedForMainPage] both queries failed:", err2.message);
      return [];
    }
  }
}
