    distributeImagesToItems: protectedProcedure.input(z2.object({
      galleryId: z2.number().int().positive(),
      imageIds: z2.array(z2.number().int().positive()).min(1).max(200),
      itemIds: z2.array(z2.number().int().positive()).min(1).max(200)
    })).mutation(async ({ input, ctx }) => {
      const { getProductGallery: getProductGallery2, assignGalleryImage: assignGalleryImage2, getRawPool: getRawPool2 } = await Promise.resolve().then(() => (init_db(), db_exports));
      const gallery = await getProductGallery2(input.galleryId);
      if (!gallery || gallery.merchantId !== ctx.user.id) throw new TRPCError3({ code: "NOT_FOUND" });
      const pool = await getRawPool2();
      const placeholders = input.imageIds.map(() => "?").join(",");
      const [imgRows] = await pool.execute(
        `SELECT * FROM productGalleryImages WHERE id IN (${placeholders}) AND merchantId = ?`,
        [...input.imageIds, ctx.user.id]
      );
      const imgMap = {};
      for (const row of imgRows) imgMap[row.id] = row;
      let assigned = 0;
      for (let i = 0; i < input.itemIds.length; i++) {
        const itemId = input.itemIds[i];
        const [maxRow] = await pool.execute(
          "SELECT COALESCE(MAX(sortOrder), -1) as maxOrder FROM productGalleryImages WHERE itemId = ?",
          [itemId]
        );
        let sortCursor = (maxRow[0]?.maxOrder ?? -1) + 1;
        for (const imageId of input.imageIds) {
          const img = imgMap[imageId];
          if (!img) continue;
          if (i === 0) {
            await assignGalleryImage2(imageId, itemId, ctx.user.id);
          } else {
            await pool.execute(
              "INSERT INTO productGalleryImages (galleryId, merchantId, itemId, imageUrl, s3Key, sortOrder) VALUES (?, ?, ?, ?, ?, ?)",
              [img.galleryId, ctx.user.id, itemId, img.imageUrl, img.s3Key ?? null, sortCursor]
            );
            const [itemRow] = await pool.execute("SELECT imageUrl FROM productGalleryItems WHERE id = ?", [itemId]);
            if (itemRow[0] && (!itemRow[0].imageUrl || itemRow[0].imageUrl === "")) {
              await pool.execute("UPDATE productGalleryItems SET imageUrl = ? WHERE id = ?", [img.imageUrl, itemId]);
            }
          }
          sortCursor++;
          assigned++;
        }
      }
      return { assigned, skipped: 0 };
    }),
