    buyItem: protectedProcedure.input(z2.object({
      itemId: z2.number().int().positive(),
      buyerNote: z2.string().max(200).optional()
    })).mutation(async ({ input, ctx }) => {
      const { getRawPool: getRawPool2 } = await Promise.resolve().then(() => (init_db(), db_exports));
      const pool = await getRawPool2();
      const [rows] = await pool.execute(
        "SELECT gi.* FROM productGalleryItems gi WHERE gi.id = ? LIMIT 1",
        [input.itemId]
      );
      const item = rows[0];
      if (!item) throw new TRPCError3({ code: "NOT_FOUND", message: "\u5546\u54C1\u4E0D\u5B58\u5728" });
      if (item.status === "hidden") throw new TRPCError3({ code: "BAD_REQUEST", message: "\u6B64\u5546\u54C1\u4E0D\u53EF\u8CFC\u8CB7" });
      if (item.status === "sold") throw new TRPCError3({ code: "BAD_REQUEST", message: "\u6B64\u5546\u54C1\u5DF2\u552E\u51FA" });
      if (item.merchantId === ctx.user.id) throw new TRPCError3({ code: "BAD_REQUEST", message: "\u4E0D\u80FD\u8CFC\u8CB7\u81EA\u5DF1\u7684\u5546\u54C1" });
      let resolvedImageUrl = item.imageUrl || "";
      if (!resolvedImageUrl) {
        try {
          const [imgRows] = await pool.execute(
            "SELECT imageUrl FROM productGalleryImages WHERE itemId = ? ORDER BY sortOrder ASC, id ASC LIMIT 1",
            [input.itemId]
          );
          resolvedImageUrl = imgRows[0]?.imageUrl || "";
        } catch {
        }
      }
      await pool.execute(
        'UPDATE productGalleryItems SET status = "sold" WHERE id = ? AND status = "active"',
        [input.itemId]
      );
      try {
        const { getOrCreateSellerDeposit: getOrCreateSellerDeposit2, createGalleryOrder: createGalleryOrder2 } = await Promise.resolve().then(() => (init_db(), db_exports));
        const deposit = await getOrCreateSellerDeposit2(item.merchantId);
        const commissionRate = parseFloat(String(deposit.productCommissionRate ?? 0.05));
        await createGalleryOrder2({
          galleryId: item.galleryId,
          galleryItemId: item.id,
          merchantId: item.merchantId,
          buyerId: ctx.user.id,
          title: item.itemName || `\u5716\u7247\u5546\u54C1 #${item.id}`,
          itemNumber: item.itemNumber || "",
          imageUrl: resolvedImageUrl,
          price: parseFloat(item.price) || 0,
          currency: item.currency || "HKD",
          commissionRate,
          buyerNote: input.buyerNote
        });
      } catch (e) {
        console.error("[markSold] createGalleryOrder failed", e);
      }
      try {
        const { openOrGetChatRoom, sendChatMessage } = await Promise.resolve().then(() => (init_db(), db_exports));
        const priceFmt = parseFloat(item.price) > 0 ? `HK$${parseFloat(item.price).toLocaleString("en-HK")}` : "\u9762\u8B70";
        const nameStr = item.itemName ? `\u300A${item.itemName}\u300B` : `\u5716\u7247\u5546\u54C1 #${item.id}`;
        const noteStr = input.buyerNote ? `
\u5099\u6CE8\uFF1A${input.buyerNote}` : "";
        const msg = `\u{1F4E6} \u8CB7\u5BB6\u5DF2\u843D\u55AE\u8CFC\u8CB7\u5716\u96C6\u5546\u54C1 ${nameStr}\uFF08${priceFmt}\uFF09${noteStr}\uFF0C\u8ACB\u76E1\u5FEB\u78BA\u8A8D\u6210\u4EA4\u3002`;
        if (openOrGetChatRoom && sendChatMessage) {
          const { roomId } = await openOrGetChatRoom(item.merchantId, ctx.user.id);
          await sendChatMessage(roomId, item.merchantId, msg, "system");
        }
      } catch {
      }
      return { ok: true };
    }),
