    userGenerateGalleryCover: protectedProcedure.input(z2.object({
      galleryId: z2.number().int().positive(),
      itemIds: z2.array(z2.number().int().positive()).min(1).optional()
    })).mutation(async ({ input, ctx }) => {
      const { getProductGallery: getProductGallery2, listProductGalleryItems: listProductGalleryItems2, updateProductGallery: updateProductGallery2 } = await Promise.resolve().then(() => (init_db(), db_exports));
      const gallery = await getProductGallery2(input.galleryId);
      if (!gallery || gallery.merchantId !== ctx.user.id) {
        throw new TRPCError3({ code: "NOT_FOUND" });
      }
      const items = await listProductGalleryItems2(input.galleryId);
      let filtered = items.filter((i) => i.imageUrl);
      if (input.itemIds && input.itemIds.length > 0) {
        const idSet = new Set(input.itemIds);
        filtered = filtered.filter((i) => idSet.has(i.id));
      }
      const imageUrls = filtered.map((i) => String(i.imageUrl)).slice(0, 9);
      if (imageUrls.length === 0) {
        throw new TRPCError3({ code: "BAD_REQUEST", message: "\u5716\u7247\u96C6\u66AB\u7121\u5546\u54C1\u5716\u7247" });
      }
      const sharp2 = (await import("sharp")).default;
      const W = 1200, H = 630;
      const cols = imageUrls.length === 1 ? 1 : imageUrls.length <= 4 ? 2 : 3;
      const rows = Math.ceil(imageUrls.length / cols);
      const cellW = Math.floor(W / cols);
      const cellH = Math.floor(H / rows);
      const composites = [];
      for (let i = 0; i < imageUrls.length; i++) {
        try {
          const resp = await fetch(imageUrls[i], { signal: AbortSignal.timeout(1e4) });
          if (!resp.ok) continue;
          const buf = Buffer.from(await resp.arrayBuffer());
          const resized = await sharp2(buf).resize(cellW, cellH, { fit: "cover", position: "centre" }).jpeg({ quality: 85 }).toBuffer();
          const col = i % cols;
          const row = Math.floor(i / cols);
          composites.push({ input: resized, left: col * cellW, top: row * cellH });
        } catch {
        }
      }
      if (composites.length === 0) {
        throw new TRPCError3({ code: "INTERNAL_SERVER_ERROR", message: "\u7121\u6CD5\u8B80\u53D6\u5716\u7247\uFF0C\u8ACB\u91CD\u8A66" });
      }
      const finalBuf = await sharp2({
        create: { width: W, height: H, channels: 3, background: { r: 20, g: 20, b: 24 } }
      }).composite(composites).jpeg({ quality: 90 }).toBuffer();
      const uid = `${Date.now()}-${Math.random().toString(36).slice(2)}`;
      const key = `user-galleries/${ctx.user.id}/cover-${uid}.jpg`;
      const { url: coverUrl } = await storagePut(key, finalBuf, "image/jpeg");
      await updateProductGallery2(input.galleryId, { coverImageUrl: coverUrl });
      return { coverImageUrl: coverUrl };
    }),
