function formatEndTime(endTime) {
  const d = new Date(endTime);
  const weekdays = ["\u65E5", "\u4E00", "\u4E8C", "\u4E09", "\u56DB", "\u4E94", "\u516D"];
  const parts = new Intl.DateTimeFormat("en-US", {
    timeZone: "Asia/Hong_Kong",
    year: "numeric",
    month: "2-digit",
    day: "2-digit",
    hour: "2-digit",
    minute: "2-digit",
    weekday: "short",
    hour12: false
  }).formatToParts(d);
  const get = (t2) => parts.find((p) => p.type === t2)?.value ?? "";
  const year = parseInt(get("year"), 10);
  const month = parseInt(get("month"), 10);
  const day = parseInt(get("day"), 10);
  const wkMap = { Sun: 0, Mon: 1, Tue: 2, Wed: 3, Thu: 4, Fri: 5, Sat: 6 };
  const weekday = weekdays[wkMap[get("weekday")] ?? 0];
  let hours = parseInt(get("hour"), 10);
  if (hours === 24) hours = 0;
  const minutes = get("minute");
  let period;
  let displayHour;
  if (hours < 6) {
    period = "\u51CC\u6668";
    displayHour = hours;
  } else if (hours < 12) {
    period = "\u4E0A\u5348";
    displayHour = hours;
  } else if (hours === 12) {
    period = "\u4E2D\u5348";
    displayHour = 12;
  } else if (hours < 18) {
    period = "\u4E0B\u5348";
    displayHour = hours - 12;
  } else {
    period = "\u665A\u4E0A";
    displayHour = hours - 12;
  }
  return `${year}\u5E74${month}\u6708${day}\u65E5 (${weekday}) ${period}${displayHour}:${minutes}`;
}
