async function setupVite(app, server) {
  const serverOptions = {
    middlewareMode: true,
    hmr: { server },
    allowedHosts: true
  };
  const vite = await createViteServer({
    ...vite_config_default,
    configFile: false,
    server: serverOptions,
    appType: "custom"
  });
  app.use(vite.middlewares);
  app.use("*", async (req, res, next) => {
    const url = req.originalUrl;
    try {
      const clientTemplate = path3.resolve(
        import.meta.dirname,
        "../..",
        "client",
        "index.html"
      );
      let template = await fs2.promises.readFile(clientTemplate, "utf-8");
      template = template.replace(
        `src="/src/main.tsx"`,
        `src="/src/main.tsx?v=${nanoid()}"`
      );
      const forwardedProto = req.headers["x-forwarded-proto"];
      const protocol = typeof forwardedProto === "string" ? forwardedProto.split(",")[0].trim() : req.protocol;
      const host = req.get("host") || "";
      const base = `${protocol}://${host}`;
      const _cleanPath = req.path.split("?")[0].replace(/\/+$/, "") || "/";
      const ogHtml = await injectOgMeta(template, _cleanPath, protocol, host) ?? await injectProductOgMeta(template, _cleanPath, protocol, host) ?? await injectCollectionPostOgMeta(template, _cleanPath, protocol, host) ?? await injectCardZzzzOgMeta(template, _cleanPath, protocol, host) ?? await injectGroupAuctionItemOgMeta(template, _cleanPath, req.query, protocol, host) ?? await injectGalleryOgMeta(template, _cleanPath, req.query, protocol, host) ?? await injectCardMarketListingOgMeta(template, _cleanPath, req.query, protocol, host) ?? injectCardMarketBrowseOgMeta(template, _cleanPath, req.query, protocol, host) ?? injectStaticPageMeta(template, _cleanPath, base);
      if (ogHtml) {
        const ua = req.headers["user-agent"] ?? "";
        const isBot = /facebookexternalhit|Twitterbot|LinkedInBot|WhatsApp|Discordbot|TelegramBot|Slackbot|ia_archiver|msnbot|googlebot|bingbot/i.test(ua);
        if (isBot) {
          res.status(200).set({ "Content-Type": "text/html" }).end(ogHtml);
          return;
        }
      }
      const page = await vite.transformIndexHtml(url, ogHtml ?? template);
      res.status(200).set({ "Content-Type": "text/html" }).end(page);
    } catch (e) {
      vite.ssrFixStacktrace(e);
      next(e);
    }
  });
}
function serveStatic(app) {
  const possiblePaths = [
    path3.resolve(import.meta.dirname, "public"),
    // Relative to dist/index.js
    path3.resolve(process.cwd(), "dist", "public"),
    // Relative to project root
    path3.resolve(process.cwd(), "public")
  ];
  let distPath = "";
  for (const p of possiblePaths) {
    console.log(`[Static] Checking path: ${p}`);
    if (fs2.existsSync(p) && fs2.existsSync(path3.join(p, "index.html"))) {
      distPath = p;
      console.log(`[Static] Found valid public directory at: ${distPath}`);
      break;
    }
  }
  if (!distPath) {
    distPath = possiblePaths[0];
    console.error(
      `[Static] ERROR: Could not find a valid build directory with index.html. Defaulting to: ${distPath}`
    );
  }
  app.get("/robots.txt", (req, res) => {
    const robotsPath = path3.resolve(distPath, "robots.txt");
    if (!fs2.existsSync(robotsPath)) {
      const defaultRobots = "User-agent: *\nAllow: /\n";
      const buf = Buffer.from(defaultRobots, "utf-8");
      const rangeHeader2 = req.headers.range;
      if (rangeHeader2) {
        const match = rangeHeader2.match(/bytes=(\d+)-(\d*)/);
        if (match) {
          const start = parseInt(match[1], 10);
          const end = match[2] ? parseInt(match[2], 10) : buf.length - 1;
          const chunk = buf.subarray(start, end + 1);
          res.status(206).set({
            "Content-Type": "text/plain; charset=utf-8",
            "Content-Range": `bytes ${start}-${end}/${buf.length}`,
            "Content-Length": chunk.length.toString(),
            "Accept-Ranges": "bytes",
            "Cache-Control": "no-store",
            "Surrogate-Control": "no-store"
          }).end(chunk);
          return;
        }
      }
      res.status(200).set({
        "Content-Type": "text/plain; charset=utf-8",
        "Accept-Ranges": "bytes",
        "Content-Length": buf.length.toString(),
        "Cache-Control": "no-store",
        "Surrogate-Control": "no-store"
      }).end(buf);
      return;
    }
    const content = fs2.readFileSync(robotsPath);
    const rangeHeader = req.headers.range;
    if (rangeHeader) {
      const match = rangeHeader.match(/bytes=(\d+)-(\d*)/);
      if (match) {
        const start = parseInt(match[1], 10);
        const end = match[2] ? parseInt(match[2], 10) : content.length - 1;
        const chunk = content.subarray(start, end + 1);
        res.status(206).set({
          "Content-Type": "text/plain; charset=utf-8",
          "Content-Range": `bytes ${start}-${end}/${content.length}`,
          "Content-Length": chunk.length.toString(),
          "Accept-Ranges": "bytes",
          "Cache-Control": "no-store",
          "Surrogate-Control": "no-store"
        }).end(chunk);
        return;
      }
    }
    res.status(200).set({
      "Content-Type": "text/plain; charset=utf-8",
      "Accept-Ranges": "bytes",
      "Transfer-Encoding": "chunked",
      "Cache-Control": "no-store",
      "Surrogate-Control": "no-store"
    });
    res.write(content);
    res.end();
  });
  app.use(express.static(distPath));
  app.use(async (req, res, next) => {
    if (req.path.startsWith("/api")) {
      return next();
    }
    const indexPath = path3.resolve(distPath, "index.html");
    if (!fs2.existsSync(indexPath)) {
      console.error(`[Static] index.html not found at: ${indexPath}`);
      res.status(500).send("Server error: index.html not found");
      return;
    }
    const forwardedProto = req.headers["x-forwarded-proto"];
    const protocol = typeof forwardedProto === "string" ? forwardedProto.split(",")[0].trim() : req.protocol;
    const host = req.get("host") || "";
    const ua = String(req.headers["user-agent"] ?? "");
    const isSocialCrawler = /facebookexternalhit|meta-externalagent|facebot|Twitterbot|LinkedInBot|WhatsApp|TelegramBot|Slackbot|Discordbot|Pinterest/i.test(ua);
    const noCacheHeaders = isSocialCrawler ? {
      "Cache-Control": "public, max-age=300, must-revalidate",
      "CDN-Cache-Control": "no-store",
      "Surrogate-Control": "no-store"
    } : {
      "Cache-Control": "private, no-store, no-cache, must-revalidate",
      "Surrogate-Control": "no-store",
      "CDN-Cache-Control": "no-store",
      "Pragma": "no-cache",
      "Vary": "*"
    };
    const base = `${protocol}://${host}`;
    const cleanPath = req.path.split("?")[0].replace(/\/+$/, "") || "/";
    let html = await fs2.promises.readFile(indexPath, "utf-8");
    const ogHtml = await injectOgMeta(html, cleanPath, protocol, host) ?? await injectProductOgMeta(html, cleanPath, protocol, host) ?? await injectCollectionPostOgMeta(html, cleanPath, protocol, host) ?? await injectCardZzzzOgMeta(html, cleanPath, protocol, host) ?? await injectGroupAuctionItemOgMeta(html, cleanPath, req.query, protocol, host) ?? await injectGalleryOgMeta(html, cleanPath, req.query, protocol, host) ?? await injectCardMarketListingOgMeta(html, cleanPath, req.query, protocol, host) ?? injectCardMarketBrowseOgMeta(html, cleanPath, req.query, protocol, host) ?? injectStaticPageMeta(html, cleanPath, base);
    if (ogHtml) {
      res.status(200).set({ "Content-Type": "text/html", ...noCacheHeaders }).end(ogHtml);
      return;
    }
    res.set(noCacheHeaders).sendFile(indexPath, (err) => {
      if (err && !res.headersSent) {
        console.error("[Static] sendFile error:", err);
        res.status(500).send("Server error");
      }
    });
  });
}

