    const existing = await db.select({ key: siteSettings2.key }).from(siteSettings2);
    const existingKeys = new Set(existing.map((r) => r.key));
    let seeded = 0;
    for (const [key, value] of Object.entries(LOYALTY_DEFAULTS)) {
      if (!existingKeys.has(key)) {
        await db.insert(siteSettings2).values({ key, value });
        seeded++;
      }
    }
